// Smart filter using Pipeline Config settings
const config = $('Parse Config').first().json;
const items = $input.all().map(i => i.json);
const results = [];

const keywords = config.mustHaveKeywords || [];
const blocked = config.blockedKeywords || [];
const blockedLocs = config.blockedLocations || [];

for (const j of items) {
  if (!j.position && !j.title) continue;
  const title = (j.position || j.title || '').toLowerCase();
  const tags = (j.tags || []).join(' ').toLowerCase();
  const loc = (j.location || '').toLowerCase();
  const all = title + ' ' + tags + ' ' + loc;

  // Must match at least one keyword
  if (!keywords.some(k => all.includes(k))) continue;

  // Must not match blocked terms
  if (blocked.some(k => title.includes(k) || tags.includes(k))) continue;

  // Must not be international
  if (blockedLocs.some(k => loc.includes(k))) continue;

  results.push({ json: j });
}

if (results.length === 0) return [{ json: { _empty: true } }];
return results;

// Rate all filtered jobs via OpenRouter in a single pass
// NO looping nodes - everything happens here
const jobs = $input.all().map(i => i.json);
const results = [];
const API_URL = 'https://openrouter.ai/api/v1/chat/completions';
const API_KEY = '[REDACTED_OPENROUTER_KEY]bbce7805776a19533d900539';
const MODEL = 'google/gemini-2.0-flash-001';
const RESUME = `Senior AI/Automation & Power Platform Engineer. 7+ years at Caterpillar Financial. Power Apps, Power Automate, Copilot Studio, Power BI, Python, Docker, Kubernetes, n8n, Zapier, Snowflake, ServiceNow, ETL pipelines. Army veteran, 2 MS degrees, Georgia Tech AI/ML Accelerator 2025. CIO Award winner. Led Copilot rollout, built AI governance chatbot (90% inquiry reduction), migrated 95% reports to Power BI.`;

// Process max 50 jobs to stay within time limits
const maxJobs = Math.min(jobs.length, 50);

for (let i = 0; i < maxJobs; i++) {
  const job = jobs[i];
  const title = job.position || job.title || 'Unknown';
  const company = job.company || 'Unknown';
  const tags = (job.tags || []).join(', ');
  const location = job.location || 'Remote';
  const desc = (job.description || '').substring(0, 1500);

  const prompt = `Rate 1-10 how well this job matches the candidate. Return ONLY a JSON object: {"rating": N, "reason": "one sentence"}

Job: ${title} at ${company}
Location: ${location}
Tags: ${tags}
Description: ${desc}

Candidate: ${RESUME}`;

  try {
    const response = await fetch(API_URL, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: MODEL,
        messages: [{ role: 'user', content: prompt }],
        temperature: 0.3,
        max_tokens: 200,
      }),
    });

    const data = await response.json();
    const content = data.choices?.[0]?.message?.content || '';

    // Parse rating from response
    let rating = 0;
    let reason = '';
    try {
      const parsed = JSON.parse(content.replace(/```json\n?/g, '').replace(/```/g, '').trim());
      rating = parsed.rating || 0;
      reason = parsed.reason || '';
    } catch {
      // Try to extract just a number
      const match = content.match(/\b(\d+)\b/);
      rating = match ? parseInt(match[1]) : 0;
      reason = content.substring(0, 100);
    }

    if (rating >= 7) {
      results.push({
        json: {
          job_title: title,
          company: company,
          location: location,
          remote_status: 'Remote',
          position_rating: rating,
          company_rating: 'N/A',
          source: 'RemoteOK',
          link: job.url ? `https://remoteok.com${job.url}` : '',
          date_added: new Date().toISOString().split('T')[0],
          applied: 'No',
          notes: reason,
          closing_date: '',
          not_aligned: 'FALSE',
          want_cover_letter: 'FALSE',
          cover_letter: '',
        }
      });
    }
  } catch (err) {
    // Skip failed jobs, continue processing
  }

  // Small delay between API calls
  if (i < maxJobs - 1) {
    await new Promise(r => setTimeout(r, 500));
  }
}

// If no high-rated jobs, return empty signal
if (results.length === 0) {
  return [{ json: { _empty: true, message: `Rated ${maxJobs} jobs, none scored 7+` } }];
}

return results;

// Generate cover letters for checked rows
const rows = $input.all().map(i => i.json);
const API_URL = 'https://openrouter.ai/api/v1/chat/completions';
const API_KEY = '[REDACTED_OPENROUTER_KEY]bbce7805776a19533d900539';
const MODEL = 'google/gemini-2.0-flash-001';
const RESUME = `Senior AI/Automation & Power Platform Engineer. 7+ years at Caterpillar Financial. Power Apps, Power Automate, Copilot Studio, Power BI, Python, Docker, Kubernetes, n8n, Zapier, Snowflake, ServiceNow, ETL pipelines. Army veteran, 2 MS degrees, Georgia Tech AI/ML Accelerator 2025. CIO Award winner. Led Copilot rollout, built AI governance chatbot (90% inquiry reduction), migrated 95% reports to Power BI.`;

const results = [];

for (const row of rows) {
  // Check: Want a Cover Letter? = TRUE and Cover Letter is empty
  const wantCL = String(row['Want a Cover Letter?'] || '').toUpperCase();
  const hasCL = String(row['Cover Letter'] || '').trim();

  if (wantCL !== 'TRUE' || hasCL.length > 10) continue;

  const title = row['Job Title'] || 'Unknown';
  const company = row['Company'] || 'Unknown';
  const location = row['Location'] || 'Remote';
  const remote = row['Remote Status'] || 'Remote';
  const rowNum = row['_rowNumber'] || row['row_number'] || 0;

  const prompt = `Write a tailored cover letter in Markdown for this role at ${company}.

# Cover Letter — ${title} at ${company}

**Aaron DeYoung**
Nashville, TN | __NOTIFICATION_EMAIL__ | 616-826-4535

---

Role: ${title}
Company: ${company}
Location: ${location} (${remote})

Resume: ${RESUME}

Write 250-350 words. Open with a company-specific hook. Include 2-3 quantified achievements. Sound human, confident, specific. End with sign-off as Aaron DeYoung, U.S. Army Veteran | AI & Automation Engineer.`;

  try {
    const response = await fetch(API_URL, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: MODEL,
        messages: [{ role: 'user', content: prompt }],
        temperature: 0.7,
        max_tokens: 1000,
      }),
    });

    const data = await response.json();
    const coverLetter = data.choices?.[0]?.message?.content || '';

    if (coverLetter.length > 50) {
      results.push({
        json: {
          ...row,
          'Cover Letter': coverLetter,
          _rowNumber: rowNum,
          _needsUpdate: true,
        }
      });
    }
  } catch (err) {
    // Skip, continue
  }

  await new Promise(r => setTimeout(r, 1000));
}

if (results.length === 0) {
  return [{ json: { _empty: true, message: 'No cover letters needed' } }];
}

return results;

// Parse Pipeline Config into structured settings
const rows = $input.all().map(i => i.json);
const config = {
  targetCompanies: [],
  mustHaveKeywords: [],
  blockedKeywords: [],
  blockedLocations: [],
  settings: {}
};

for (const row of rows) {
  if (row.Active !== 'TRUE' && row.Active !== true) continue;
  const cat = (row.Category || '').trim();
  const val = (row.Value || '').trim().toLowerCase();

  if (cat === 'Target Company') config.targetCompanies.push(val);
  else if (cat === 'Must-Have Keyword') config.mustHaveKeywords.push(val);
  else if (cat === 'Blocked Keyword') config.blockedKeywords.push(val);
  else if (cat === 'Blocked Location') config.blockedLocations.push(val);
  else if (cat === 'Setting') {
    const [key, value] = val.split('=');
    if (key && value) config.settings[key.trim()] = value.trim();
  }
}

return [{ json: config }];
